KeyEventResult _viewerOnKeyEvent(
  _FractalViewerScreenState state,
  BuildContext context,
  KeyEvent event,
) {
  if (event is! KeyDownEvent) {
    return KeyEventResult.ignored;
  }

  final controller = state._activeController(context);
  const panStep = 0.08;

  if (event.logicalKey == LogicalKeyboardKey.arrowLeft) {
    final pan = controller.view.pan;
    controller.updatePan(Vector2(pan.x - panStep, pan.y));
    state._onAutoExploreUserCorrection();
    return KeyEventResult.handled;
  }
  if (event.logicalKey == LogicalKeyboardKey.arrowRight) {
    final pan = controller.view.pan;
    controller.updatePan(Vector2(pan.x + panStep, pan.y));
    state._onAutoExploreUserCorrection();
    return KeyEventResult.handled;
  }
  if (event.logicalKey == LogicalKeyboardKey.arrowUp) {
    final pan = controller.view.pan;
    controller.updatePan(Vector2(pan.x, pan.y - panStep));
    state._onAutoExploreUserCorrection();
    return KeyEventResult.handled;
  }
  if (event.logicalKey == LogicalKeyboardKey.arrowDown) {
    final pan = controller.view.pan;
    controller.updatePan(Vector2(pan.x, pan.y + panStep));
    state._onAutoExploreUserCorrection();
    return KeyEventResult.handled;
  }
  if (event.logicalKey == LogicalKeyboardKey.minus ||
      event.logicalKey == LogicalKeyboardKey.numpadSubtract) {
    controller.updateZoom(controller.view.zoom / 1.2);
    state._onAutoExploreUserCorrection();
    return KeyEventResult.handled;
  }
  if (event.logicalKey == LogicalKeyboardKey.equal ||
      event.logicalKey == LogicalKeyboardKey.numpadAdd) {
    controller.updateZoom(controller.view.zoom * 1.2);
    state._onAutoExploreUserCorrection();
    return KeyEventResult.handled;
  }
  if (event.logicalKey == LogicalKeyboardKey.keyR) {
    controller.resetView();
    state._onAutoExploreUserCorrection();
    return KeyEventResult.handled;
  }

  return KeyEventResult.ignored;
}

void _viewerEnsureCompareController(
  _FractalViewerScreenState state,
  BuildContext context,
) {
  if (state._compareController != null) return;
  final registry = context.read<ModuleRegistry>();
  state._compareController = FractalController(registry);

  // Initialize B from A.
  final a = context.read<FractalController>();
  state._compareController!.selectModule(a.module, animate: false);
  for (final entry in a.params.entries) {
    state._compareController!.updateParam(entry.key, entry.value);
  }
  state._compareController!.updatePan(a.view.pan);
  state._compareController!.updateZoom(a.view.zoom);
  state._compareController!.updateRotation(a.view.rotation);
  state._compareController!.setTransparentBackground(a.transparentBackground);
}

/// Why a module is included or skipped by random viewer navigation.
enum ViewerRandomFractalCandidateReason {
  eligible,
  currentModule,
  diagnosticModule,
}

/// Replayable candidate decision for the random-fractal navigation action.
///
/// The runtime path receives the full registry and used to hide diagnostics via
/// broad substring checks. Keeping the decision pure makes dropped real catalog
/// IDs and leaked debug modules visible in focused tests.
@visibleForTesting
final class ViewerRandomFractalCandidate {
  final String moduleId;
  final ViewerRandomFractalCandidateReason reason;

  const ViewerRandomFractalCandidate._({
    required this.moduleId,
    required this.reason,
  });

  factory ViewerRandomFractalCandidate.fromModule(
    FractalModule module, {
    required String currentModuleId,
  }) {
    if (module.id == currentModuleId) {
      return ViewerRandomFractalCandidate._(
        moduleId: module.id,
        reason: ViewerRandomFractalCandidateReason.currentModule,
      );
    }
    if (_isDiagnosticModule(module)) {
      return ViewerRandomFractalCandidate._(
        moduleId: module.id,
        reason: ViewerRandomFractalCandidateReason.diagnosticModule,
      );
    }
    return ViewerRandomFractalCandidate._(
      moduleId: module.id,
      reason: ViewerRandomFractalCandidateReason.eligible,
    );
  }

  bool get isEligible => reason == ViewerRandomFractalCandidateReason.eligible;

  static const Set<String> _diagnosticModuleIds = {
    'test_always_red',
    'test_uniform_only',
    'test_minimal',
    'test_gl_fragcoord',
    'test_flutter_coord',
    'gpu_gradient',
    'gpu_sampler_diag',
  };

  static bool _isDiagnosticModule(FractalModule module) {
    return _diagnosticModuleIds.contains(module.id) ||
        module.shaderAsset.startsWith('shaders/diagnostic/');
  }
}

void _viewerJumpToRandomFractal(
  _FractalViewerScreenState state,
  BuildContext context,
) {
  state._log.info('action', 'Random fractal');
  final registry = context.read<ModuleRegistry>();
  final controller = context.read<FractalController>();
  final currentId = controller.module.id;
  // Filter to real fractals (skip diagnostics)
  final candidates = registry.modules
      .where(
        (m) => ViewerRandomFractalCandidate.fromModule(
          m,
          currentModuleId: currentId,
        ).isEligible,
      )
      .toList();
  if (candidates.isEmpty) return;
  final rng = math.Random();
  final pick = candidates[rng.nextInt(candidates.length)];
  controller.selectModule(pick);
}

void _viewerOnRandomFractalFab(
  _FractalViewerScreenState state,
  BuildContext context,
) {
  // Random jump is an explicit user command; stop auto-zoom first so
  // navigation does not continue moving the view on the newly selected fractal.
  state._autoExploreService?.stop();

  state._jumpToRandomFractal(context);
  AccessibilityService.announce('Random fractal selected');
  HapticService.light();
}

import 'package:flutter_fractals/core/models/fractal_preset.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/features/viewer/fractal_viewer_screen.dart';
import 'package:flutter_test/flutter_test.dart';

FractalModule _module({
  required String id,
  String? shaderAsset,
}) {
  return FractalModule(
    id: id,
    displayName: (_) => id,
    dimension: FractalDimension.twoD,
    shaderAsset: shaderAsset ?? 'shaders/$id.frag',
    parameters: const [],
    defaultPreset: FractalPreset(
      id: '$id-default',
      moduleId: id,
      name: 'Default',
      params: const {},
      view: FractalViewState.initial(),
      createdAt: DateTime(2026),
      isBuiltIn: true,
    ),
    builtInPresets: const [],
    setUniforms: (_, __, ___, ____) {},
  );
}

void main() {
  group('ViewerRandomFractalCandidate', () {
    test('excludes the currently selected module by exact id', () {
      final decision = ViewerRandomFractalCandidate.fromModule(
        _module(id: 'mandelbrot'),
        currentModuleId: 'mandelbrot',
      );

      expect(decision.moduleId, 'mandelbrot');
      expect(decision.reason, ViewerRandomFractalCandidateReason.currentModule);
      expect(decision.isEligible, isFalse);
    });

    test('keeps real catalog ids containing diag eligible', () {
      final decision = ViewerRandomFractalCandidate.fromModule(
        _module(id: 'farey_diagram'),
        currentModuleId: 'mandelbrot',
      );

      expect(decision.reason, ViewerRandomFractalCandidateReason.eligible);
      expect(decision.isEligible, isTrue);
    });

    test('excludes debug diagnostic modules from random navigation', () {
      final decisions = [
        ViewerRandomFractalCandidate.fromModule(
          _module(
            id: 'test_minimal',
            shaderAsset: 'shaders/diagnostic/test_minimal.frag',
          ),
          currentModuleId: 'mandelbrot',
        ),
        ViewerRandomFractalCandidate.fromModule(
          _module(id: 'gpu_gradient'),
          currentModuleId: 'mandelbrot',
        ),
        ViewerRandomFractalCandidate.fromModule(
          _module(id: 'gpu_sampler_diag'),
          currentModuleId: 'mandelbrot',
        ),
      ];

      expect(
        decisions.map((decision) => decision.reason),
        everyElement(ViewerRandomFractalCandidateReason.diagnosticModule),
      );
      expect(decisions.map((decision) => decision.isEligible),
          everyElement(isFalse));
    });
  });
}

import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/features/catalog/catalog_entry.dart';
import 'package:flutter_fractals/l10n/app_localizations.dart';

/// Replayable catalog search query used by the catalog screen.
///
/// The UI debounces text input, then filters entries by localized display name,
/// aliases, stable catalog ID, and category. Keeping the case/whitespace
/// normalization in one pure value object makes search behavior testable without
/// pumping the whole catalog widget.
final class CatalogSearchQuery {
  const CatalogSearchQuery._(this.value);

  factory CatalogSearchQuery.fromText(String text) {
    return CatalogSearchQuery._(text.trim().toLowerCase());
  }

  /// Lower-case, trimmed query text.
  final String value;

  bool get isEmpty => value.isEmpty;

  bool matches(CatalogEntry entry, AppLocalizations l10n) {
    if (isEmpty) return true;

    return _searchableFields(entry, l10n).any(
      (field) => field.toLowerCase().contains(value),
    );
  }

  Iterable<String> _searchableFields(
    CatalogEntry entry,
    AppLocalizations l10n,
  ) sync* {
    yield entry.module.displayName(l10n);
    yield* entry.aliases;
    yield entry.catalogId;
    yield entry.category;
  }
}

/// Dimension/category refinement selected in the catalog filter bar.
enum CatalogDimensionFilter { all, twoD, threeD, kaleidoscope }

/// Immutable catalog filter inputs for one replayable filter pass.
final class CatalogFilterCriteria {
  final String query;
  final CatalogDimensionFilter dimensionFilter;
  final String? selectedCategory;

  const CatalogFilterCriteria({
    required this.query,
    this.dimensionFilter = CatalogDimensionFilter.all,
    this.selectedCategory,
  });

  CatalogSearchQuery get searchQuery => CatalogSearchQuery.fromText(query);

  bool get hasActiveRefinements =>
      !searchQuery.isEmpty ||
      dimensionFilter != CatalogDimensionFilter.all ||
      selectedCategory != null;
}

/// Replayable catalog filter outputs consumed by the screen.
///
/// The catalog UI needs three related entry sets from one query snapshot:
/// filtered cards, dimension-chip counts, and category-chip counts. Keeping them
/// together prevents count chips and displayed cards from drifting when a search,
/// dimension, or category refinement is active.
final class CatalogFilterResult {
  final List<CatalogEntry> filteredEntries;
  final List<CatalogEntry> dimensionBaseEntries;
  final List<CatalogEntry> categoryBaseEntries;
  final Map<CatalogDimensionFilter, int> dimensionCounts;
  final Map<String, int> categoryCounts;
  final List<String> sortedCategories;

  const CatalogFilterResult._({
    required this.filteredEntries,
    required this.dimensionBaseEntries,
    required this.categoryBaseEntries,
    required this.dimensionCounts,
    required this.categoryCounts,
    required this.sortedCategories,
  });

  int countForDimension(CatalogDimensionFilter filter) =>
      dimensionCounts[filter] ?? 0;
}

/// Pure catalog filter/count contract shared by UI and tests.
final class CatalogFilter {
  const CatalogFilter._();

  static CatalogFilterResult apply({
    required Iterable<CatalogEntry> entries,
    required CatalogFilterCriteria criteria,
    required AppLocalizations l10n,
  }) {
    final query = criteria.searchQuery;
    final matchesSearch = entries
        .where((entry) => query.matches(entry, l10n))
        .toList(growable: false);

    final dimensionBaseEntries = matchesSearch
        .where(
          (entry) => _matchesSelectedCategory(entry, criteria.selectedCategory),
        )
        .toList(growable: false);
    final dimensionCounts = Map<CatalogDimensionFilter, int>.unmodifiable({
      CatalogDimensionFilter.all: dimensionBaseEntries.length,
      CatalogDimensionFilter.twoD: dimensionBaseEntries
          .where(
            (entry) => matchesDimension(entry, CatalogDimensionFilter.twoD),
          )
          .length,
      CatalogDimensionFilter.threeD: dimensionBaseEntries
          .where(
            (entry) => matchesDimension(entry, CatalogDimensionFilter.threeD),
          )
          .length,
      CatalogDimensionFilter.kaleidoscope: dimensionBaseEntries
          .where(
            (entry) => matchesDimension(
              entry,
              CatalogDimensionFilter.kaleidoscope,
            ),
          )
          .length,
    });

    final categoryBaseEntries = matchesSearch
        .where((entry) => matchesDimension(entry, criteria.dimensionFilter))
        .toList(growable: false);
    final categoryCounts = countCategories(categoryBaseEntries);
    final sortedCategories = sortCategories(
      categoryCounts,
      selectedCategory: criteria.selectedCategory,
    );

    final filteredEntries = categoryBaseEntries
        .where(
          (entry) => _matchesSelectedCategory(entry, criteria.selectedCategory),
        )
        .toList(growable: false);

    return CatalogFilterResult._(
      filteredEntries: filteredEntries,
      dimensionBaseEntries: dimensionBaseEntries,
      categoryBaseEntries: categoryBaseEntries,
      dimensionCounts: dimensionCounts,
      categoryCounts: categoryCounts,
      sortedCategories: sortedCategories,
    );
  }

  static bool matchesDimension(
    CatalogEntry entry,
    CatalogDimensionFilter filter,
  ) {
    switch (filter) {
      case CatalogDimensionFilter.all:
        return true;
      case CatalogDimensionFilter.twoD:
        return entry.module.dimension == FractalDimension.twoD;
      case CatalogDimensionFilter.threeD:
        return entry.module.dimension == FractalDimension.threeD;
      case CatalogDimensionFilter.kaleidoscope:
        return entry.category.toLowerCase().contains('kaleidoscope');
    }
  }

  static Map<String, int> countCategories(Iterable<CatalogEntry> entries) {
    final counts = <String, int>{};
    for (final entry in entries) {
      counts.update(entry.category, (count) => count + 1, ifAbsent: () => 1);
    }
    return Map<String, int>.unmodifiable(counts);
  }

  static List<String> sortCategories(
    Map<String, int> categoryCounts, {
    String? selectedCategory,
  }) {
    final categories = categoryCounts.keys.toList()
      ..sort((a, b) {
        final countCompare = (categoryCounts[b] ?? 0).compareTo(
          categoryCounts[a] ?? 0,
        );
        if (countCompare != 0) return countCompare;
        return a.compareTo(b);
      });

    if (selectedCategory != null && !categories.contains(selectedCategory)) {
      categories.insert(0, selectedCategory);
    }

    return List<String>.unmodifiable(categories);
  }

  static bool _matchesSelectedCategory(
    CatalogEntry entry,
    String? selectedCategory,
  ) {
    return selectedCategory == null || entry.category == selectedCategory;
  }
}

import 'package:flutter/foundation.dart';
import 'package:flutter_fractals/core/modules/builders/escape_time/catalog.dart';
import 'package:flutter_fractals/core/modules/builders/raymarched_3d/catalog.dart';
import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/core/modules/module_registry.dart';
import 'package:flutter_fractals/features/catalog/catalog_entry.dart';

/// Catalog data source for the Explore screen.
///
/// Phase 1: derives entries from currently implemented modules while assigning
/// stable catalog IDs. This keeps IDs future-proof for PRD-200 ingest.
class CatalogRepository {
  final List<CatalogEntry> entries;

  const CatalogRepository({required this.entries});

  factory CatalogRepository.fromRegistry(ModuleRegistry registry) {
    final categoriesById = {
      for (final config in escapeTimeCatalog) config.id: config.category,
      for (final config in raymarched3DCatalog) config.id: config.category,
    };

    return CatalogRepository(
      entries: registry.modules
          .map(
            (module) => CatalogEntry(
              // Stable prefix to decouple future module refactors from IDs.
              catalogId: 'core.${module.id}',
              module: module,
              category: categoriesById[module.id] ??
                  (module.dimension == FractalDimension.threeD
                      ? '3D Fractals'
                      : 'Other'),
            ),
          )
          .toList(growable: false),
    );
  }

  CatalogEntry byCatalogId(String catalogId) {
    return entries.firstWhere((entry) => entry.catalogId == catalogId);
  }

  @visibleForTesting
  Set<String> allIds() => entries.map((e) => e.catalogId).toSet();
}

