export 'package:flutter_fractals/core/models/wallpaper/wallpaper_target.dart';

/// Lightweight post-processing overlays to improve icon/clock legibility.
enum WallpaperStyle {
  plain,
  homeOptimized,
  lockOptimized,
}

class WallpaperOptions extends Equatable {
  final WallpaperTarget target;
  final WallpaperStyle style;

  /// If true, also saves a copy to the app export folder (and can be shared).
  final bool saveCopy;

  const WallpaperOptions({
    this.target = WallpaperTarget.home,
    this.style = WallpaperStyle.homeOptimized,
    this.saveCopy = false,
  });

  WallpaperOptions copyWith({
    WallpaperTarget? target,
    WallpaperStyle? style,
    bool? saveCopy,
  }) {
    return WallpaperOptions(
      target: target ?? this.target,
      style: style ?? this.style,
      saveCopy: saveCopy ?? this.saveCopy,
    );
  }

  @override
  List<Object?> get props => [target, style, saveCopy];
}

/// Platform wallpaper destinations supported by the native wallpaper channel.
///
/// The enum [name] values are the serialized MethodChannel contract used by
/// Android (`home`, `lock`, and `both`). Keep this model separate from the
/// service so wallpaper options can depend on the value type without importing
/// platform integration code.
enum WallpaperTarget {
  home,
  lock,
  both,
}

import 'dart:io';

import 'package:flutter/foundation.dart';
import 'package:flutter/services.dart';
import 'package:flutter_fractals/core/models/wallpaper/wallpaper_target.dart';

export 'package:flutter_fractals/core/models/wallpaper/wallpaper_target.dart';

/// Sets the generated fractal as the device wallpaper.
///
/// Platform notes:
/// - Android: uses [android.app.WallpaperManager] to set HOME/LOCK/BOTH.
/// - iOS: iOS does not allow setting wallpaper programmatically. We save the
///   image to Photos instead (so the user can set it from the Photos app).
class WallpaperService {
  static const MethodChannel _channel =
      MethodChannel('com.fractalforge/wallpaper');

  const WallpaperService();

  Future<bool> setWallpaper(
    Uint8List pngBytes, {
    required WallpaperTarget target,
  }) async {
    if (kIsWeb) {
      throw UnsupportedError('Wallpaper setting is not supported on web.');
    }

    if (Platform.isIOS) {
      // iOS does not allow programmatic wallpaper setting. Save to Photos.
      return saveToPhotos(pngBytes);
    }

    final ok = await _channel.invokeMethod<bool>('setWallpaper', {
      'bytes': pngBytes,
      'target': target.name,
    });

    return ok ?? false;
  }

  Future<bool> saveToPhotos(Uint8List pngBytes) async {
    if (kIsWeb) {
      throw UnsupportedError('Saving to Photos is not supported on web.');
    }

    final ok = await _channel.invokeMethod<bool>('saveToPhotos', {
      'bytes': pngBytes,
    });

    return ok ?? false;
  }
}

