import 'dart:collection';
import 'dart:math' as math;
import 'package:flutter/foundation.dart';
import 'package:flutter/scheduler.dart';
import 'package:flutter_fractals/core/services/app_logger_service.dart';

/// Performance metrics collected during rendering.
///
/// Contains frame timing, shader compilation, and memory usage data.
@immutable
class PerformanceMetrics {
  /// Average frame time in milliseconds.
  final double avgFrameTimeMs;

  /// Minimum frame time in milliseconds.
  final double minFrameTimeMs;

  /// Maximum frame time in milliseconds.
  final double maxFrameTimeMs;

  /// 95th percentile frame time in milliseconds.
  final double p95FrameTimeMs;

  /// 99th percentile frame time in milliseconds.
  final double p99FrameTimeMs;

  /// Number of frames rendered.
  final int frameCount;

  /// Number of dropped frames (> 16.67ms).
  final int droppedFrames;

  /// Current frames per second.
  final double fps;

  /// Number of shader compilations detected.
  final int shaderCompilations;

  /// Memory usage in megabytes (if available).
  final double? memoryUsageMb;

  /// Peak memory usage in megabytes.
  final double? peakMemoryMb;

  /// Whether the app is currently experiencing jank.
  final bool isJanky;

  /// Total profiling duration in seconds.
  final double durationSeconds;

  /// Frame time stability score (0-100, 100 = perfectly stable).
  final double stabilityScore;

  const PerformanceMetrics({
    required this.avgFrameTimeMs,
    required this.minFrameTimeMs,
    required this.maxFrameTimeMs,
    required this.p95FrameTimeMs,
    required this.p99FrameTimeMs,
    required this.frameCount,
    required this.droppedFrames,
    required this.fps,
    required this.shaderCompilations,
    this.memoryUsageMb,
    this.peakMemoryMb,
    this.isJanky = false,
    required this.durationSeconds,
    required this.stabilityScore,
  });

  /// Creates empty metrics.
  const PerformanceMetrics.empty()
      : avgFrameTimeMs = 0,
        minFrameTimeMs = 0,
        maxFrameTimeMs = 0,
        p95FrameTimeMs = 0,
        p99FrameTimeMs = 0,
        frameCount = 0,
        droppedFrames = 0,
        fps = 0,
        shaderCompilations = 0,
        memoryUsageMb = null,
        peakMemoryMb = null,
        isJanky = false,
        durationSeconds = 0,
        stabilityScore = 100;

  /// Frame drop percentage (0-100).
  double get dropPercentage =>
      frameCount > 0 ? (droppedFrames / frameCount) * 100 : 0;

  /// Whether performance is considered good (> 55 FPS, < 5% drops).
  bool get isGood => fps >= 55 && dropPercentage < 5;

  /// Whether performance is acceptable (> 30 FPS, < 15% drops).
  bool get isAcceptable => fps >= 30 && dropPercentage < 15;

  @override
  String toString() => 'PerformanceMetrics(fps: ${fps.toStringAsFixed(1)}, '
      'avg: ${avgFrameTimeMs.toStringAsFixed(2)}ms, '
      'dropped: $droppedFrames/$frameCount)';
}

/// A single frame timing sample.
@immutable
class FrameSample {
  final Duration timestamp;
  final double frameTimeMs;
  final bool wasDropped;
  final bool hadShaderCompile;

  const FrameSample({
    required this.timestamp,
    required this.frameTimeMs,
    required this.wasDropped,
    this.hadShaderCompile = false,
  });
}

/// Replayable accepted/rejected frame sample window.
///
/// Public tests and future telemetry replays can construct [FrameSample]
/// directly. Keep the aggregation candidate step explicit so malformed frame
/// timings cannot poison averages, percentiles, FPS, or jank status with NaN.
@visibleForTesting
class PerformanceFrameSampleWindow {
  final List<FrameSample> acceptedSamples;
  final int rejectedSampleCount;

  const PerformanceFrameSampleWindow._({
    required this.acceptedSamples,
    required this.rejectedSampleCount,
  });

  factory PerformanceFrameSampleWindow.fromSamples(
    Iterable<FrameSample> samples,
  ) {
    final accepted = <FrameSample>[];
    var rejected = 0;

    for (final sample in samples) {
      if (_hasUsableFrameTime(sample.frameTimeMs)) {
        accepted.add(sample);
      } else {
        rejected++;
      }
    }

    return PerformanceFrameSampleWindow._(
      acceptedSamples: List<FrameSample>.unmodifiable(accepted),
      rejectedSampleCount: rejected,
    );
  }

  bool get isEmpty => acceptedSamples.isEmpty;

  List<double> sortedFrameTimes() => acceptedSamples
      .map((sample) => sample.frameTimeMs)
      .toList(growable: false)
    ..sort();

  Iterable<FrameSample> recentSamples({int limit = 10}) =>
      acceptedSamples.reversed.take(limit);

  static bool _hasUsableFrameTime(double frameTimeMs) {
    return frameTimeMs.isFinite && frameTimeMs > 0.0;
  }
}

/// Pure calculator for replayable frame-time metrics.
///
/// [PerformanceService] collects frame samples from a ticker. Keeping the
/// aggregation rules here makes percentile and jank assumptions testable
/// without a live scheduler.
@visibleForTesting
class PerformanceMetricsCalculator {
  const PerformanceMetricsCalculator._();

  static PerformanceMetrics fromSamples({
    required Iterable<FrameSample> samples,
    required int shaderCompilations,
    required double durationSeconds,
    double? memoryUsageMb,
    double? peakMemoryMb,
    double targetFrameTimeMs = PerformanceService.targetFrameTimeMs,
  }) {
    final sampleWindow = PerformanceFrameSampleWindow.fromSamples(samples);
    if (sampleWindow.isEmpty) {
      return const PerformanceMetrics.empty();
    }

    final sampleList = sampleWindow.acceptedSamples;
    final frameTimes = sampleWindow.sortedFrameTimes();

    final avg = frameTimes.reduce((a, b) => a + b) / frameTimes.length;
    final min = frameTimes.first;
    final max = frameTimes.last;

    final p95Index = nearestRankPercentileIndex(
      sampleCount: frameTimes.length,
      percentile: 0.95,
    );
    final p99Index = nearestRankPercentileIndex(
      sampleCount: frameTimes.length,
      percentile: 0.99,
    );
    final p95 = frameTimes[p95Index];
    final p99 = frameTimes[p99Index];

    final droppedFrames = sampleList.where((s) => s.wasDropped).length;
    final fps = avg > 0 ? 1000.0 / avg : 0.0;

    final variance =
        frameTimes.map((t) => (t - avg) * (t - avg)).reduce((a, b) => a + b) /
            frameTimes.length;
    final stdDev = variance > 0 ? variance.sqrt() : 0;
    final stabilityScore =
        (100 - (stdDev / targetFrameTimeMs * 100)).clamp(0.0, 100.0);

    final recentSamples = sampleWindow.recentSamples();
    final recentDrops = recentSamples.where((s) => s.wasDropped).length;
    final isJanky = recentDrops > 3;

    return PerformanceMetrics(
      avgFrameTimeMs: avg,
      minFrameTimeMs: min,
      maxFrameTimeMs: max,
      p95FrameTimeMs: p95,
      p99FrameTimeMs: p99,
      frameCount: sampleList.length,
      droppedFrames: droppedFrames,
      fps: fps,
      shaderCompilations: shaderCompilations,
      memoryUsageMb: memoryUsageMb,
      peakMemoryMb:
          peakMemoryMb != null && peakMemoryMb > 0 ? peakMemoryMb : null,
      isJanky: isJanky,
      durationSeconds: durationSeconds,
      stabilityScore: stabilityScore,
    );
  }

  @visibleForTesting
  static int nearestRankPercentileIndex({
    required int sampleCount,
    required double percentile,
  }) {
    assert(sampleCount > 0, 'sampleCount must be positive');
    assert(
      percentile > 0.0 && percentile <= 1.0,
      'percentile must be in the nearest-rank interval (0, 1]',
    );

    final rank = (sampleCount * percentile).ceil();
    return (rank - 1).clamp(0, sampleCount - 1).toInt();
  }
}

/// Replayable cadence for sample-window side effects.
///
/// [PerformanceService] keeps only the latest 300 samples. Cadence decisions
/// must use the total number of recorded samples, not the retained queue length,
/// otherwise every frame after the queue caps at 300 looks like an interval hit.
@visibleForTesting
class PerformanceSampleCadence {
  static const int metricsIntervalSamples = 30;
  static const int snapshotLogIntervalSamples = 60;

  final int retainedSampleCount;
  final int totalSamplesRecorded;

  const PerformanceSampleCadence({
    required this.retainedSampleCount,
    required this.totalSamplesRecorded,
  })  : assert(
            retainedSampleCount >= 0, 'retainedSampleCount cannot be negative'),
        assert(totalSamplesRecorded >= 0,
            'totalSamplesRecorded cannot be negative'),
        assert(
          retainedSampleCount <= totalSamplesRecorded,
          'retained samples cannot exceed total recorded samples',
        );

  bool get retainedWindowIsCapped => totalSamplesRecorded > retainedSampleCount;

  bool get shouldUpdateMemoryUsage => _isIntervalHit(metricsIntervalSamples);

  bool get shouldUpdateMetrics => _isIntervalHit(metricsIntervalSamples);

  bool get shouldLogSnapshot => _isIntervalHit(snapshotLogIntervalSamples);

  bool _isIntervalHit(int interval) {
    return totalSamplesRecorded > 0 && totalSamplesRecorded % interval == 0;
  }
}

/// Service for collecting and analyzing rendering performance.
///
/// Tracks frame times, detects shader compilation stalls, and monitors
/// memory usage to provide real-time performance metrics.
class PerformanceService extends ChangeNotifier {
  static const int _maxSamples = 300; // ~5 seconds at 60fps
  static const double _targetFrameTime = 16.67; // 60 FPS
  static const double _shaderStallThreshold =
      100.0; // 100ms suggests compilation

  @visibleForTesting
  static const double targetFrameTimeMs = _targetFrameTime;

  final Queue<FrameSample> _samples = Queue();
  Ticker? _ticker;
  Duration _lastFrameTime = Duration.zero;
  Stopwatch? _sessionStopwatch;

  bool _isRunning = false;
  int _shaderCompilations = 0;
  int _totalSamplesRecorded = 0;
  double _peakMemoryMb = 0;
  PerformanceMetrics _currentMetrics = const PerformanceMetrics.empty();

  /// Whether performance tracking is currently active.
  bool get isRunning => _isRunning;

  /// Current performance metrics.
  PerformanceMetrics get metrics => _currentMetrics;

  /// Most recent frame samples for graphing.
  List<FrameSample> get samples => _samples.toList();

  /// Starts performance tracking.
  ///
  /// Attaches to the scheduler's ticker to measure frame times.
  void start(TickerProvider vsync) {
    if (_isRunning) return;

    _isRunning = true;
    _samples.clear();
    _shaderCompilations = 0;
    _totalSamplesRecorded = 0;
    _peakMemoryMb = 0;
    _lastFrameTime = Duration.zero;
    _sessionStopwatch = Stopwatch()..start();

    _ticker = vsync.createTicker(_onTick);
    _ticker!.start();

    notifyListeners();
  }

  /// Stops performance tracking.
  void stop() {
    if (!_isRunning) return;

    _ticker?.stop();
    _ticker?.dispose();
    _ticker = null;
    _sessionStopwatch?.stop();
    _isRunning = false;

    _updateMetrics();
    notifyListeners();
  }

  /// Resets all collected metrics.
  void reset() {
    _samples.clear();
    _shaderCompilations = 0;
    _totalSamplesRecorded = 0;
    _peakMemoryMb = 0;
    _currentMetrics = const PerformanceMetrics.empty();
    _sessionStopwatch?.reset();
    if (_isRunning) {
      _sessionStopwatch?.start();
    }
    notifyListeners();
  }

  void _onTick(Duration elapsed) {
    if (_lastFrameTime == Duration.zero) {
      _lastFrameTime = elapsed;
      return;
    }

    final frameTimeMs = (elapsed - _lastFrameTime).inMicroseconds / 1000.0;
    _lastFrameTime = elapsed;

    // Detect shader compilation stalls
    final hadShaderCompile = frameTimeMs > _shaderStallThreshold;
    if (hadShaderCompile) {
      _shaderCompilations++;
    }

    final sample = FrameSample(
      timestamp: elapsed,
      frameTimeMs: frameTimeMs,
      wasDropped: frameTimeMs > _targetFrameTime,
      hadShaderCompile: hadShaderCompile,
    );

    _samples.addLast(sample);
    _totalSamplesRecorded++;
    if (_samples.length > _maxSamples) {
      _samples.removeFirst();
    }

    final cadence = PerformanceSampleCadence(
      retainedSampleCount: _samples.length,
      totalSamplesRecorded: _totalSamplesRecorded,
    );

    // Update memory tracking periodically
    if (cadence.shouldUpdateMemoryUsage) {
      _updateMemoryUsage();
    }

    // Update metrics every ~0.5 seconds (30 frames)
    if (cadence.shouldUpdateMetrics) {
      _updateMetrics();
      notifyListeners();
    }

    // Log performance snapshot every ~1 second (60 frames) — sampled to avoid noise
    if (cadence.shouldLogSnapshot) {
      _logPerformanceSnapshot();
    }
  }

  /// Logs a concise FPS/frame-time snapshot via [AppLogger].
  void _logPerformanceSnapshot() {
    final m = _currentMetrics;
    if (m.frameCount == 0) return;
    AppLogger.instance.debug('perf', 'fps_snapshot', data: {
      'fps': m.fps.toStringAsFixed(1),
      'avg_ms': m.avgFrameTimeMs.toStringAsFixed(2),
      'p95_ms': m.p95FrameTimeMs.toStringAsFixed(2),
      'dropped': m.droppedFrames,
      'frames': m.frameCount,
    });
  }

  void _updateMemoryUsage() {
    // Note: In Flutter, getting exact memory usage requires platform channels
    // or debug mode APIs. This is a simplified approach using heuristics.
    // For accurate memory profiling, use DevTools or platform-specific APIs.

    // Placeholder: In real app, use PlatformDispatcher.instance.onReportTimings
    // or implement platform channels for memory stats
  }

  void _updateMetrics() {
    _currentMetrics = PerformanceMetricsCalculator.fromSamples(
      samples: _samples,
      shaderCompilations: _shaderCompilations,
      durationSeconds: (_sessionStopwatch?.elapsedMilliseconds ?? 0) / 1000.0,
      memoryUsageMb: null, // Platform-specific
      peakMemoryMb: _peakMemoryMb,
    );
  }

  /// Gets a formatted summary of the current performance.
  String getSummary() {
    final m = _currentMetrics;
    final buffer = StringBuffer();

    buffer.writeln('=== Performance Summary ===');
    buffer.writeln('Duration: ${m.durationSeconds.toStringAsFixed(1)}s');
    buffer
        .writeln('FPS: ${m.fps.toStringAsFixed(1)} (${_getFpsRating(m.fps)})');
    buffer.writeln('Frame Time: ${m.avgFrameTimeMs.toStringAsFixed(2)}ms avg');
    buffer.writeln('  Min: ${m.minFrameTimeMs.toStringAsFixed(2)}ms');
    buffer.writeln('  Max: ${m.maxFrameTimeMs.toStringAsFixed(2)}ms');
    buffer.writeln('  P95: ${m.p95FrameTimeMs.toStringAsFixed(2)}ms');
    buffer.writeln('  P99: ${m.p99FrameTimeMs.toStringAsFixed(2)}ms');
    buffer.writeln(
        'Dropped Frames: ${m.droppedFrames}/${m.frameCount} (${m.dropPercentage.toStringAsFixed(1)}%)');
    buffer.writeln('Shader Compilations: ${m.shaderCompilations}');
    buffer
        .writeln('Stability Score: ${m.stabilityScore.toStringAsFixed(0)}/100');

    return buffer.toString();
  }

  String _getFpsRating(double fps) {
    if (fps >= 58) return 'Excellent';
    if (fps >= 50) return 'Good';
    if (fps >= 30) return 'Acceptable';
    return 'Poor';
  }

  @override
  void dispose() {
    stop();
    super.dispose();
  }
}

/// Extension for calculating square root on doubles.
extension DoubleExtension on double {
  double sqrt() => this >= 0 ? math.sqrt(this) : 0;
}

import 'package:flutter_test/flutter_test.dart';
import 'package:flutter_fractals/core/services/performance_service.dart';

void main() {
  group('PerformanceMetrics', () {
    test('empty metrics have default values', () {
      const metrics = PerformanceMetrics.empty();

      expect(metrics.avgFrameTimeMs, 0);
      expect(metrics.fps, 0);
      expect(metrics.frameCount, 0);
      expect(metrics.droppedFrames, 0);
      expect(metrics.stabilityScore, 100);
      expect(metrics.isJanky, false);
    });

    test('calculates drop percentage correctly', () {
      const metrics = PerformanceMetrics(
        avgFrameTimeMs: 16.67,
        minFrameTimeMs: 15.0,
        maxFrameTimeMs: 20.0,
        p95FrameTimeMs: 18.0,
        p99FrameTimeMs: 19.0,
        frameCount: 100,
        droppedFrames: 10,
        fps: 60,
        shaderCompilations: 0,
        durationSeconds: 1.67,
        stabilityScore: 90,
      );

      expect(metrics.dropPercentage, 10.0);
    });

    test('isGood returns true for excellent performance', () {
      const metrics = PerformanceMetrics(
        avgFrameTimeMs: 16.0,
        minFrameTimeMs: 15.0,
        maxFrameTimeMs: 17.0,
        p95FrameTimeMs: 16.5,
        p99FrameTimeMs: 17.0,
        frameCount: 100,
        droppedFrames: 3,
        fps: 60,
        shaderCompilations: 0,
        durationSeconds: 1.67,
        stabilityScore: 95,
      );

      expect(metrics.isGood, true);
      expect(metrics.isAcceptable, true);
    });

    test('isGood returns false for poor performance', () {
      const metrics = PerformanceMetrics(
        avgFrameTimeMs: 40.0,
        minFrameTimeMs: 30.0,
        maxFrameTimeMs: 80.0,
        p95FrameTimeMs: 60.0,
        p99FrameTimeMs: 75.0,
        frameCount: 100,
        droppedFrames: 50,
        fps: 25,
        shaderCompilations: 2,
        durationSeconds: 4.0,
        stabilityScore: 40,
      );

      expect(metrics.isGood, false);
      expect(metrics.isAcceptable, false);
    });

    test('isAcceptable returns true for moderate performance', () {
      const metrics = PerformanceMetrics(
        avgFrameTimeMs: 25.0,
        minFrameTimeMs: 20.0,
        maxFrameTimeMs: 35.0,
        p95FrameTimeMs: 30.0,
        p99FrameTimeMs: 33.0,
        frameCount: 100,
        droppedFrames: 12,
        fps: 40,
        shaderCompilations: 1,
        durationSeconds: 2.5,
        stabilityScore: 75,
      );

      expect(metrics.isGood, false);
      expect(metrics.isAcceptable, true);
    });
  });

  group('FrameSample', () {
    test('creates sample with correct values', () {
      const sample = FrameSample(
        timestamp: Duration(milliseconds: 1000),
        frameTimeMs: 16.67,
        wasDropped: false,
        hadShaderCompile: false,
      );

      expect(sample.timestamp.inMilliseconds, 1000);
      expect(sample.frameTimeMs, 16.67);
      expect(sample.wasDropped, false);
      expect(sample.hadShaderCompile, false);
    });

    test('identifies dropped frames', () {
      const sample = FrameSample(
        timestamp: Duration(milliseconds: 1000),
        frameTimeMs: 33.34,
        wasDropped: true,
        hadShaderCompile: false,
      );

      expect(sample.wasDropped, true);
    });

    test('identifies shader compilation stalls', () {
      const sample = FrameSample(
        timestamp: Duration(milliseconds: 1000),
        frameTimeMs: 150.0,
        wasDropped: true,
        hadShaderCompile: true,
      );

      expect(sample.hadShaderCompile, true);
    });
  });

  group('PerformanceMetricsCalculator', () {
    test('uses nearest-rank percentile indices without one-based drift', () {
      final samples = [
        for (var i = 1; i <= 100; i++)
          FrameSample(
            timestamp: Duration(milliseconds: i),
            frameTimeMs: i.toDouble(),
            wasDropped: false,
          ),
      ];

      final metrics = PerformanceMetricsCalculator.fromSamples(
        samples: samples,
        shaderCompilations: 0,
        durationSeconds: 1.0,
      );

      expect(metrics.p95FrameTimeMs, 95.0);
      expect(metrics.p99FrameTimeMs, 99.0);
    });

    test('ignores malformed frame timings before computing metrics', () {
      const samples = [
        FrameSample(
          timestamp: Duration(milliseconds: 1),
          frameTimeMs: double.nan,
          wasDropped: true,
        ),
        FrameSample(
          timestamp: Duration(milliseconds: 2),
          frameTimeMs: double.infinity,
          wasDropped: true,
        ),
        FrameSample(
          timestamp: Duration(milliseconds: 3),
          frameTimeMs: -5,
          wasDropped: true,
        ),
        FrameSample(
          timestamp: Duration(milliseconds: 4),
          frameTimeMs: 16,
          wasDropped: false,
        ),
        FrameSample(
          timestamp: Duration(milliseconds: 5),
          frameTimeMs: 33,
          wasDropped: true,
        ),
      ];

      final sampleWindow = PerformanceFrameSampleWindow.fromSamples(samples);
      final metrics = PerformanceMetricsCalculator.fromSamples(
        samples: samples,
        shaderCompilations: 0,
        durationSeconds: 1.0,
      );

      expect(sampleWindow.rejectedSampleCount, 3);
      expect(sampleWindow.acceptedSamples.map((sample) => sample.frameTimeMs), [
        16,
        33,
      ]);
      expect(metrics.frameCount, 2);
      expect(metrics.droppedFrames, 1);
      expect(metrics.avgFrameTimeMs, 24.5);
      expect(metrics.minFrameTimeMs, 16);
      expect(metrics.maxFrameTimeMs, 33);
      expect(metrics.p95FrameTimeMs, 33);
      expect(metrics.p99FrameTimeMs, 33);
      expect(metrics.fps, predicate<double>((value) => value.isFinite));
    });
  });

  group('PerformanceSampleCadence', () {
    test('keeps update cadence tied to total frames after sample window caps',
        () {
      expect(
        const PerformanceSampleCadence(
          retainedSampleCount: 300,
          totalSamplesRecorded: 300,
        ).shouldUpdateMetrics,
        isTrue,
      );
      expect(
        const PerformanceSampleCadence(
          retainedSampleCount: 300,
          totalSamplesRecorded: 301,
        ).shouldUpdateMetrics,
        isFalse,
      );
      expect(
        const PerformanceSampleCadence(
          retainedSampleCount: 300,
          totalSamplesRecorded: 330,
        ).shouldUpdateMetrics,
        isTrue,
      );
      expect(
        const PerformanceSampleCadence(
          retainedSampleCount: 300,
          totalSamplesRecorded: 301,
        ).shouldLogSnapshot,
        isFalse,
      );
      expect(
        const PerformanceSampleCadence(
          retainedSampleCount: 300,
          totalSamplesRecorded: 360,
        ).shouldLogSnapshot,
        isTrue,
      );
    });
  });

  group('PerformanceService', () {
    test('starts in stopped state', () {
      final service = PerformanceService();

      expect(service.isRunning, false);
      expect(service.metrics.frameCount, 0);
      expect(service.samples, isEmpty);
    });

    test('reset clears all data', () {
      final service = PerformanceService();

      // Add some dummy state (if we could run it)
      service.reset();

      expect(service.samples, isEmpty);
      expect(service.metrics.frameCount, 0);
      expect(service.metrics.shaderCompilations, 0);
    });

    test('getSummary returns formatted string', () {
      final service = PerformanceService();
      final summary = service.getSummary();

      expect(summary, contains('Performance Summary'));
      expect(summary, contains('FPS:'));
      expect(summary, contains('Frame Time:'));
      expect(summary, contains('Dropped Frames:'));
    });

    test('disposes cleanly', () {
      final service = PerformanceService();

      // Should not throw
      expect(() => service.dispose(), returnsNormally);
    });
  });

  group('DoubleExtension', () {
    test('sqrt works for positive numbers', () {
      expect(4.0.sqrt(), closeTo(2.0, 0.001));
      expect(9.0.sqrt(), closeTo(3.0, 0.001));
      expect(16.0.sqrt(), closeTo(4.0, 0.001));
    });

    test('sqrt returns 0 for negative numbers', () {
      expect((-4.0).sqrt(), 0);
      expect((-1.0).sqrt(), 0);
    });

    test('sqrt of zero is zero', () {
      expect(0.0.sqrt(), 0);
    });
  });
}

import 'package:flutter_test/flutter_test.dart';
import 'package:flutter_fractals/features/renderer/deep_zoom_precision_policy.dart';

void main() {
  const policy = DeepZoomPrecisionPolicy();

  group('DeepZoomPrecisionPolicy.thresholdsFor', () {
    test('exposes contiguous Mandelbrot df2 to CPU fallback boundaries', () {
      final thresholds = policy.thresholdsFor('mandelbrot');

      expect(thresholds.supportsDoubleFloat, isTrue);
      expect(thresholds.doubleFloatLowerZoom, 5e6);
      expect(thresholds.doubleFloatUpperZoom, thresholds.cpuFallbackZoom);
      expect(thresholds.shouldUseDoubleFloat(1e11), isTrue);
      expect(
        thresholds.shouldUseDoubleFloat(thresholds.cpuFallbackZoom),
        isFalse,
      );
      expect(
        thresholds.shouldUseCpuFallback(thresholds.cpuFallbackZoom),
        isTrue,
      );
    });

    test('exposes default thresholds without a double-float range', () {
      final thresholds = policy.thresholdsFor('unknown_fractal');

      expect(thresholds.cpuFallbackZoom, 1e7);
      expect(thresholds.supportsDoubleFloat, isFalse);
      expect(thresholds.shouldUseDoubleFloat(1e10), isFalse);
    });
  });

  group('DeepZoomPrecisionPolicy.decisionFor', () {
    test('exposes CPU and double-float routing from one threshold snapshot',
        () {
      final decision = policy.decisionFor(moduleId: 'mandelbrot', zoom: 1e10);

      expect(decision.moduleId, 'mandelbrot');
      expect(decision.zoom, 1e10);
      expect(decision.cpuFallbackZoom, 1e12);
      expect(decision.shouldUseDoubleFloat, isTrue);
      expect(decision.shouldUseCpuFallback, isFalse);
      expect(decision.thresholds, same(policy.thresholdsFor('mandelbrot')));
    });

    test('keeps invalid zoom samples below precision routing thresholds', () {
      for (final zoom in [double.nan, double.negativeInfinity]) {
        final decision = policy.decisionFor(
          moduleId: 'mandelbrot',
          zoom: zoom,
        );

        expect(decision.shouldUseDoubleFloat, isFalse, reason: '$zoom');
        expect(decision.shouldUseCpuFallback, isFalse, reason: '$zoom');
      }
    });
  });

  group('DeepZoomPrecisionPolicy.shouldUseCpuFallback', () {
    test('returns false for mandelbrot at zoom 1e6', () {
      expect(
        policy.shouldUseCpuFallback(moduleId: 'mandelbrot', zoom: 1e6),
        isFalse,
      );
    });

    test('returns true for mandelbrot at zoom 1e15', () {
      expect(
        policy.shouldUseCpuFallback(moduleId: 'mandelbrot', zoom: 1e15),
        isTrue,
      );
    });

    test('uses default threshold for unknown module', () {
      // Default threshold is 1e7; zoom just below should be false.
      expect(
        policy.shouldUseCpuFallback(moduleId: 'unknown_fractal', zoom: 9.9e6),
        isFalse,
      );
      // At or above default threshold (1e7) should be true.
      expect(
        policy.shouldUseCpuFallback(moduleId: 'unknown_fractal', zoom: 1e7),
        isTrue,
      );
    });
  });

  group('DeepZoomPrecisionPolicy.shouldUseDoubleFloat', () {
    test('returns true for mandelbrot in df2 range', () {
      // df2 range: [5e6, 1e12)
      expect(
        policy.shouldUseDoubleFloat(moduleId: 'mandelbrot', zoom: 5e6),
        isTrue,
      );
      expect(
        policy.shouldUseDoubleFloat(moduleId: 'mandelbrot', zoom: 1e10),
        isTrue,
      );
    });

    test('returns false for non-mandelbrot modules', () {
      expect(
        policy.shouldUseDoubleFloat(moduleId: 'julia', zoom: 1e10),
        isFalse,
      );
      expect(
        policy.shouldUseDoubleFloat(moduleId: 'burning_ship', zoom: 1e10),
        isFalse,
      );
    });

    test('returns false below df2 lower threshold', () {
      // Below 5e6 the standard float32 shader is sufficient.
      expect(
        policy.shouldUseDoubleFloat(moduleId: 'mandelbrot', zoom: 1e5),
        isFalse,
      );
      expect(
        policy.shouldUseDoubleFloat(moduleId: 'mandelbrot', zoom: 4.9e6),
        isFalse,
      );
    });

    test('returns false at or above df2 upper threshold', () {
      // At 1e12 CPU fallback takes over; df2 should not be active.
      expect(
        policy.shouldUseDoubleFloat(moduleId: 'mandelbrot', zoom: 1e12),
        isFalse,
      );
    });
  });

  group('DeepZoomPrecisionPolicy.scaledGpuIterations', () {
    test('returns base at zoom 1', () {
      expect(
        policy.scaledGpuIterations(baseIterations: 256, zoom: 1.0),
        equals(256),
      );
    });

    test('returns base at zoom below 1', () {
      expect(
        policy.scaledGpuIterations(baseIterations: 256, zoom: 0.5),
        equals(256),
      );
    });

    test('increases with zoom depth', () {
      final atZoom1 =
          policy.scaledGpuIterations(baseIterations: 256, zoom: 1.0);
      final atZoom1e6 =
          policy.scaledGpuIterations(baseIterations: 256, zoom: 1e6);
      expect(atZoom1e6, greaterThan(atZoom1));
    });

    test('clamps to gpuMaxIterations', () {
      // Very high base + very high zoom should be clamped.
      final result = policy.scaledGpuIterations(
        baseIterations: DeepZoomPrecisionPolicy.gpuMaxIterations,
        zoom: 1e30,
      );
      expect(result, equals(DeepZoomPrecisionPolicy.gpuMaxIterations));
    });

    test('clamps low base to minimum of 4', () {
      final result = policy.scaledGpuIterations(baseIterations: 1, zoom: 1.0);
      expect(result, equals(4));
    });

    test('treats non-finite zoom values as bounded inputs', () {
      expect(
        policy.scaledGpuIterations(baseIterations: 256, zoom: double.nan),
        equals(256),
      );
      expect(
        policy.scaledGpuIterations(baseIterations: 256, zoom: double.infinity),
        equals(DeepZoomPrecisionPolicy.gpuMaxIterations),
      );
      expect(
        policy.scaledGpuIterations(
          baseIterations: 256,
          zoom: double.negativeInfinity,
        ),
        equals(256),
      );
    });
  });

  group('DeepZoomHysteresisState', () {
    test('exposes replayable streak transitions', () {
      const initial = DeepZoomHysteresisState.initial();

      final first = initial.next(
        nextModuleId: 'julia',
        overThreshold: true,
        activationFrames: 2,
      );
      final second = first.next(
        nextModuleId: 'julia',
        overThreshold: true,
        activationFrames: 2,
      );
      final resetByZoomOut = second.next(
        nextModuleId: 'julia',
        overThreshold: false,
        activationFrames: 2,
      );
      final resetByModule = first.next(
        nextModuleId: 'mandelbrot',
        overThreshold: true,
        activationFrames: 2,
      );

      expect(first.moduleId, 'julia');
      expect(first.aboveThresholdCount, 1);
      expect(first.cpuActive, isFalse);
      expect(second.aboveThresholdCount, 2);
      expect(second.cpuActive, isTrue);
      expect(resetByZoomOut.aboveThresholdCount, 0);
      expect(resetByZoomOut.cpuActive, isFalse);
      expect(resetByModule.moduleId, 'mandelbrot');
      expect(resetByModule.aboveThresholdCount, 1);
      expect(resetByModule.cpuActive, isFalse);
    });
  });

  group('DeepZoomHysteresis', () {
    test('does not activate CPU until hysteresisFrames consecutive frames', () {
      final hysteresis = DeepZoomHysteresis(policy: policy);
      // mandelbrot CPU threshold is 1e12; zoom 2e12 is above it.
      const moduleId = 'mandelbrot';
      const highZoom = 2e12;
      final frames = policy.hysteresisFrames;

      // All frames before the last should still return false.
      for (var i = 0; i < frames - 1; i++) {
        expect(
          hysteresis.update(moduleId: moduleId, zoom: highZoom),
          isFalse,
          reason: 'frame $i should not activate CPU yet',
        );
      }

      // The hysteresisFrames-th frame should activate.
      expect(
        hysteresis.update(moduleId: moduleId, zoom: highZoom),
        isTrue,
      );
    });

    test('drops back to GPU immediately when zoom falls below threshold', () {
      final hysteresis = DeepZoomHysteresis(policy: policy);
      const moduleId = 'mandelbrot';
      const highZoom = 2e14;
      const lowZoom = 1.0;
      final frames = policy.hysteresisFrames;

      // Trigger CPU mode.
      for (var i = 0; i < frames; i++) {
        hysteresis.update(moduleId: moduleId, zoom: highZoom);
      }

      // A single below-threshold update drops back to GPU.
      expect(
        hysteresis.update(moduleId: moduleId, zoom: lowZoom),
        isFalse,
      );
    });

    test('does not carry above-threshold count across module changes', () {
      final hysteresis = DeepZoomHysteresis(policy: policy);

      expect(
        hysteresis.update(moduleId: 'julia', zoom: 2e9),
        isFalse,
        reason: 'first Julia deep-zoom frame should only prime hysteresis',
      );

      expect(
        hysteresis.update(moduleId: 'mandelbrot', zoom: 2e14),
        isFalse,
        reason: 'first Mandelbrot deep-zoom frame must not inherit Julia count',
      );

      expect(
        hysteresis.update(moduleId: 'mandelbrot', zoom: 2e14),
        isTrue,
        reason: 'second consecutive Mandelbrot deep-zoom frame activates CPU',
      );
    });

    test('reset clears state so hysteresis counter restarts', () {
      final hysteresis = DeepZoomHysteresis(policy: policy);
      const moduleId = 'mandelbrot';
      const highZoom = 2e14;
      final frames = policy.hysteresisFrames;

      // Build up to just before activation.
      for (var i = 0; i < frames - 1; i++) {
        hysteresis.update(moduleId: moduleId, zoom: highZoom);
      }

      hysteresis.reset();

      // After reset, the counter is zero; a single update should not activate.
      expect(
        hysteresis.update(moduleId: moduleId, zoom: highZoom),
        isFalse,
      );
    });
  });
}

import 'dart:typed_data';

import 'package:flutter_fractals/features/renderer/cpu_fractal_renderer.dart';
import 'package:flutter_fractals/features/renderer/deep_zoom_precision_policy.dart';
import 'package:flutter_test/flutter_test.dart';
import 'package:vector_math/vector_math.dart';

void main() {
  group('DeepZoomPrecisionPolicy', () {
    const policy = DeepZoomPrecisionPolicy();

    test('uses per-fractal thresholds for CPU fallback', () {
      // Mandelbrot: df2 shader covers [5e6, 1e12), CPU above 1e12.
      expect(policy.thresholdFor('mandelbrot'), 1e12);
      // Escape-time fractals: GPU precision degrades around ~1e9.
      expect(policy.thresholdFor('julia'), 1e9);
      expect(policy.thresholdFor('celtic'), 1e9);
      expect(policy.thresholdFor('buffalo'), 1e9);
      expect(policy.thresholdFor('burning_ship'), 1e9);
      expect(policy.thresholdFor('tricorn'), 1e9);
      expect(policy.thresholdFor('phoenix'), 1e9);
    });

    test('provides default threshold for unlisted fractals', () {
      // Default threshold is 1e7 for safe float32 precision.
      expect(policy.thresholdFor('some_unknown'), 1e7);
    });

    test('fallback toggles at threshold', () {
      // GPU stays active for Mandelbrot until df2 upper bound.
      expect(
        policy.shouldUseCpuFallback(moduleId: 'mandelbrot', zoom: 1e7),
        isFalse,
      );
      expect(
        policy.shouldUseCpuFallback(moduleId: 'mandelbrot', zoom: 1e12),
        isTrue,
      );
      // Unlisted fractals use default threshold (1e7)
      // 'some_unknown' is not in the per-module map, so it gets _defaultThreshold.
      expect(
        policy.shouldUseCpuFallback(moduleId: 'some_unknown', zoom: 5e6),
        isFalse,
      );
      expect(
        policy.shouldUseCpuFallback(moduleId: 'some_unknown', zoom: 1e7),
        isTrue,
      );
    });

    test('auto-scales GPU iterations with zoom depth', () {
      expect(policy.scaledGpuIterations(baseIterations: 120, zoom: 1.0), 120);

      final mid = policy.scaledGpuIterations(baseIterations: 120, zoom: 1e6);
      final deep = policy.scaledGpuIterations(baseIterations: 120, zoom: 1e12);

      expect(mid, greaterThan(120));
      expect(deep, greaterThan(mid));
      expect(deep, lessThanOrEqualTo(DeepZoomPrecisionPolicy.gpuMaxIterations));

      // Clamp behavior.
      expect(
        policy.scaledGpuIterations(baseIterations: 5000, zoom: 1e30),
        DeepZoomPrecisionPolicy.gpuMaxIterations,
      );
    });
  });

  group('CPU deep-zoom quality', () {
    test('supersampling reduces grain by at least 10%', () async {
      const width = 120;
      const height = 120;

      final base = await renderCpuFrame(
        moduleId: 'mandelbrot',
        viewPan: Vector2(-0.743643887, 0.131825904),
        viewZoom: 320.0,
        iterations: 320,
        bailout: 4.0,
        juliaC: Vector2(-0.8, 0.156),
        width: width,
        height: height,
        sampleCount: 1,
      );

      final improved = await renderCpuFrame(
        moduleId: 'mandelbrot',
        viewPan: Vector2(-0.743643887, 0.131825904),
        viewZoom: 320.0,
        iterations: 320,
        bailout: 4.0,
        juliaC: Vector2(-0.8, 0.156),
        width: width,
        height: height,
        sampleCount: 4,
      );

      final baseGrain = computeGrainScore(base.rgba, width, height);
      final improvedGrain = computeGrainScore(improved.rgba, width, height);

      expect(improvedGrain, lessThan(baseGrain * 0.90));
    });

    test('supports celtic and buffalo formulas in CPU path', () async {
      final celtic = await renderCpuFrame(
        moduleId: 'celtic',
        viewPan: Vector2(-0.45, 0.22),
        viewZoom: 90.0,
        iterations: 280,
        bailout: 4.0,
        juliaC: Vector2.zero(),
        width: 64,
        height: 64,
      );

      final buffalo = await renderCpuFrame(
        moduleId: 'buffalo',
        viewPan: Vector2(-0.35, 0.3),
        viewZoom: 90.0,
        iterations: 280,
        bailout: 4.0,
        juliaC: Vector2.zero(),
        width: 64,
        height: 64,
      );

      expect(celtic.rgba.length, 64 * 64 * 4);
      expect(buffalo.rgba.length, 64 * 64 * 4);

      bool hasVariation(Uint8List rgba) {
        final first = rgba[0];
        for (final v in rgba) {
          if (v != first) return true;
        }
        return false;
      }

      expect(hasVariation(celtic.rgba), isTrue);
      expect(hasVariation(buffalo.rgba), isTrue);
    });
  });
}

import 'dart:math' as math;

import 'package:flutter/foundation.dart';

const double _mandelbrotDf2LowerThreshold = 5e6;
const double _mandelbrotDf2UpperThreshold = 1e12;
const double _escapeTimeCpuFallbackThreshold = 1e9;
const double _defaultCpuFallbackThreshold = 1e7;

/// Describes the precision boundaries for one fractal module.
@immutable
class DeepZoomThresholds {
  final double cpuFallbackZoom;
  final double? doubleFloatLowerZoom;
  final double? doubleFloatUpperZoom;

  const DeepZoomThresholds({
    required this.cpuFallbackZoom,
    this.doubleFloatLowerZoom,
    this.doubleFloatUpperZoom,
  })  : assert(
          (doubleFloatLowerZoom == null) == (doubleFloatUpperZoom == null),
          'double-float ranges must provide both lower and upper bounds',
        ),
        assert(
          (doubleFloatLowerZoom ?? double.negativeInfinity) <
              (doubleFloatUpperZoom ?? double.infinity),
          'double-float lower bound must be below upper bound',
        ),
        assert(
          (doubleFloatUpperZoom ?? double.negativeInfinity) <= cpuFallbackZoom,
          'double-float range must end no later than CPU fallback',
        );

  bool get supportsDoubleFloat => doubleFloatLowerZoom != null;

  bool shouldUseCpuFallback(double zoom) => zoom >= cpuFallbackZoom;

  bool shouldUseDoubleFloat(double zoom) {
    final lower = doubleFloatLowerZoom;
    final upper = doubleFloatUpperZoom;
    if (lower == null || upper == null) return false;
    return zoom >= lower && zoom < upper;
  }
}

/// Replayable precision routing decision for a module/zoom sample.
///
/// Renderer code needs CPU fallback and double-float eligibility to agree on
/// the same threshold snapshot. Keeping both booleans with their source
/// thresholds exposes that data-flow instead of recomputing partial decisions
/// at separate call sites.
@immutable
class DeepZoomPrecisionDecision {
  final String moduleId;
  final double zoom;
  final DeepZoomThresholds thresholds;

  const DeepZoomPrecisionDecision({
    required this.moduleId,
    required this.zoom,
    required this.thresholds,
  });

  bool get shouldUseCpuFallback => thresholds.shouldUseCpuFallback(zoom);
  bool get shouldUseDoubleFloat => thresholds.shouldUseDoubleFloat(zoom);
  double get cpuFallbackZoom => thresholds.cpuFallbackZoom;
}

/// Decides when GPU precision is likely insufficient at deep zoom.
///
/// ## Float32 precision analysis
///
/// GPU fragment shaders use float32 arithmetic (~7 significant digits,
/// mantissa ≈ 2^-24 ≈ 6e-8).
///
/// The coordinate span per pixel is: span_per_px = fractal_range / (zoom * resolution)
///   For a 1080p display and a fractal range of ~3 units:
///     span_per_px = 3 / (zoom * 1920) ≈ 1.6e-3 / zoom
///
/// Float32 artifacts appear when the per-pixel span drops below the
/// representable precision at the current center offset. In the worst case
/// (center near origin, no cancellation) this is roughly:
///     artifact threshold zoom ≈ 1.6e-3 / 6e-8 ≈ 2.7e4  ... but only at
///     an offset of ~1.0 unit from origin. Deep in the Mandelbrot boundary
///     where |c| ≈ 2, precision is consumed faster (≈ 1e4–1e5).
///     With the standard center at (0,0) or a well-normalized fractal,
///     artifacts are not visible until zoom ≈ 1e6–1e8.
///
/// Our shaders perform double-width emulation via paired float32 values
/// (see shader uniform layout) for a subset of fractals, extending usable
/// GPU range to ~1e12 before requiring CPU.
///
/// ## Conservative threshold policy
///
/// These thresholds are intentionally HIGH so GPU is used as long as
/// possible. The CPU fallback is a correctness escape hatch, not a
/// performance choice — it is significantly slower and disables GPU effects.
///
/// Raise these thresholds if you observe visible precision artifacts before
/// the switch; lower them only if tested on a low-DPI device where artifacts
/// appear earlier.
@immutable
class DeepZoomPrecisionPolicy {
  /// Maximum iterations we send to GPU shaders for real-time rendering.
  ///
  /// Most escape-time shaders clamp around this value already; keeping the
  /// cap centralized avoids overdriving slower devices at extreme zoom.
  static const int gpuMaxIterations = 2000;

  /// Per-module GPU→CPU fallback thresholds.
  ///
  /// For mandelbrot, the CPU fallback threshold is pushed to the df2 upper
  /// bound because the double-float shader [mandelbrot_df2.frag] covers the
  /// intermediate zoom range before CPU fallback.
  ///
  /// Other escape-time fractals still use float32 GPU up to their threshold,
  /// then fall back to CPU (no df2 variant available yet).
  static const Map<String, DeepZoomThresholds> _moduleThresholds = {
    // Mandelbrot: df2 shader covers zoom [5e6, 1e12), so CPU fallback only
    // kicks in at 1e12 (the df2 upper bound).
    'mandelbrot': DeepZoomThresholds(
      cpuFallbackZoom: _mandelbrotDf2UpperThreshold,
      doubleFloatLowerZoom: _mandelbrotDf2LowerThreshold,
      doubleFloatUpperZoom: _mandelbrotDf2UpperThreshold,
    ),
    // Julia & related escape-time fractals: GPU precision degrades sooner,
    // so switch to CPU around ~1e9.
    'julia': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'celtic': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'buffalo': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'burning_ship': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'tricorn': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'multibrot3': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'multibrot4': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'multibrot5': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'phoenix': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
  };

  /// Default threshold for any fractal type not listed above.
  /// Simple orbit fractals and non-escape-time types lose precision more
  /// slowly; 1e7 is a conservative upper bound for float32 at 1080p.
  static const DeepZoomThresholds _defaultThresholds = DeepZoomThresholds(
    cpuFallbackZoom: _defaultCpuFallbackThreshold,
  );

  /// Number of consecutive evaluations above the zoom threshold required
  /// before committing to CPU fallback. Prevents rapid GPU↔CPU flicker
  /// when zooming near the boundary.
  static const int _hysteresisFrames = 2;

  const DeepZoomPrecisionPolicy();

  /// Returns true when GPU precision is insufficient at the given zoom.
  ///
  /// Pure, stateless evaluation — callers that want hysteresis should
  /// use [DeepZoomHysteresis] to track frame counts.
  bool shouldUseCpuFallback({
    required String moduleId,
    required double zoom,
  }) {
    return decisionFor(moduleId: moduleId, zoom: zoom).shouldUseCpuFallback;
  }

  DeepZoomThresholds thresholdsFor(String moduleId) =>
      _moduleThresholds[moduleId] ?? _defaultThresholds;

  DeepZoomPrecisionDecision decisionFor({
    required String moduleId,
    required double zoom,
  }) {
    return DeepZoomPrecisionDecision(
      moduleId: moduleId,
      zoom: zoom,
      thresholds: thresholdsFor(moduleId),
    );
  }

  double thresholdFor(String moduleId) =>
      thresholdsFor(moduleId).cpuFallbackZoom;

  /// Returns true when the double-float shader should be used for [moduleId].
  ///
  /// Currently only mandelbrot has a df2 variant. The range is exclusive of
  /// the CPU fallback threshold.
  bool shouldUseDoubleFloat({
    required String moduleId,
    required double zoom,
  }) {
    return decisionFor(moduleId: moduleId, zoom: zoom).shouldUseDoubleFloat;
  }

  int get hysteresisFrames => _hysteresisFrames;

  /// Auto-scales iteration count with zoom depth for GPU rendering.
  ///
  /// Keeps shallow zoom responsive while increasing detail as zoom grows,
  /// reducing under-iteration artifacts in deep zoom.
  ///
  /// Scaling curve:
  /// - zoom <= 1: unchanged
  /// - zoom > 1: base * (1 + 0.35 * log10(zoom))
  /// - clamped to [4, gpuMaxIterations]
  int scaledGpuIterations({
    required int baseIterations,
    required double zoom,
  }) {
    final safeBase = baseIterations.clamp(4, gpuMaxIterations);
    final depth = _zoomDepthLog10(zoom);
    if (depth == 0.0) return safeBase;

    final factor = 1.0 + 0.35 * depth;
    final scaled = (safeBase * factor).round();
    return scaled.clamp(4, gpuMaxIterations);
  }
}

double _zoomDepthLog10(double zoom) {
  if (zoom.isNaN || zoom <= 1.0) return 0.0;
  if (zoom.isInfinite) return 30.0;
  return (math.log(zoom) / math.ln10).clamp(0.0, 30.0);
}

/// Replayable state for one GPU→CPU deep-zoom hysteresis streak.
///
/// Keeping the transition pure makes the hidden state/order dependence visible:
/// streaks are scoped to one module, below-threshold samples reset immediately,
/// and CPU fallback activates only after enough consecutive above-threshold
/// samples for the same module.
@immutable
class DeepZoomHysteresisState {
  final String? moduleId;
  final int aboveThresholdCount;
  final bool cpuActive;

  const DeepZoomHysteresisState({
    required this.moduleId,
    required this.aboveThresholdCount,
    required this.cpuActive,
  });

  const DeepZoomHysteresisState.initial()
      : moduleId = null,
        aboveThresholdCount = 0,
        cpuActive = false;

  DeepZoomHysteresisState next({
    required String nextModuleId,
    required bool overThreshold,
    required int activationFrames,
  }) {
    assert(activationFrames > 0, 'activationFrames must be positive');
    final sameModule = moduleId == nextModuleId;
    final currentCount = sameModule ? aboveThresholdCount : 0;

    if (!overThreshold) {
      return DeepZoomHysteresisState(
        moduleId: nextModuleId,
        aboveThresholdCount: 0,
        cpuActive: false,
      );
    }

    final nextCount = currentCount + 1;
    return DeepZoomHysteresisState(
      moduleId: nextModuleId,
      aboveThresholdCount: nextCount,
      cpuActive: nextCount >= activationFrames,
    );
  }
}

/// Stateful hysteresis filter for GPU→CPU deep-zoom transitions.
///
/// Wraps [DeepZoomPrecisionPolicy] and requires [policy.hysteresisFrames]
/// consecutive above-threshold evaluations before reporting CPU needed.
/// Drops back to GPU immediately when zoom falls below threshold.
class DeepZoomHysteresis {
  final DeepZoomPrecisionPolicy policy;
  DeepZoomHysteresisState _state = const DeepZoomHysteresisState.initial();

  DeepZoomHysteresis({this.policy = const DeepZoomPrecisionPolicy()});

  DeepZoomHysteresisState get state => _state;

  /// Call this on every zoom change. Returns true if CPU fallback is warranted.
  bool update({required String moduleId, required double zoom}) {
    final overThreshold = policy.shouldUseCpuFallback(
      moduleId: moduleId,
      zoom: zoom,
    );

    _state = _state.next(
      nextModuleId: moduleId,
      overThreshold: overThreshold,
      activationFrames: policy.hysteresisFrames,
    );
    return _state.cpuActive;
  }

  void reset() {
    _state = const DeepZoomHysteresisState.initial();
  }
}

