/// Replayable thumbnail asset plan for one catalog entry.
///
/// Catalog IDs are stable public IDs such as `core.mandelbrot`, while asset
/// thumbnails are stored by raw module ID under `assets/catalog_thumbs/`.
/// Keeping that mapping pure makes thumbnail provenance testable without
/// pumping the catalog widget.
final class CatalogThumbnailPlan {
  final String catalogId;
  final String assetId;

  const CatalogThumbnailPlan._({
    required this.catalogId,
    required this.assetId,
  });

  factory CatalogThumbnailPlan.fromCatalogId(String catalogId) {
    return CatalogThumbnailPlan._(
      catalogId: catalogId,
      assetId: assetIdForCatalogId(catalogId),
    );
  }

  String get assetPath => 'assets/catalog_thumbs/$assetId.png';

  static String assetIdForCatalogId(String catalogId) {
    return catalogId.startsWith('core.') ? catalogId.substring(5) : catalogId;
  }
}

/// Replayable visibility state for catalog thumbnail provenance labels.
///
/// The catalog used to rely on a hand-maintained list of IDs that supposedly
/// had exact thumbnails. That list drifted behind generated assets, so real
/// PNG thumbnails could be shown with an incorrect "Preview approximate" label.
/// Treat image load success/failure as the source of truth instead.
final class CatalogThumbnailLoadState {
  final bool imageLoaded;
  final bool imageError;

  const CatalogThumbnailLoadState({
    required this.imageLoaded,
    required this.imageError,
  });

  bool get showsLoadingPlaceholder => !imageLoaded && !imageError;
  bool get showsFallbackPreview => imageError;
  bool get isApproximatePreview => showsFallbackPreview;
}

import 'dart:io';

import 'package:flutter_fractals/features/catalog/catalog_thumbnail_plan.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('CatalogThumbnailPlan', () {
    test('maps core catalog IDs to catalog thumbnail asset paths', () {
      final plan = CatalogThumbnailPlan.fromCatalogId('core.mandelbrot');

      expect(plan.catalogId, 'core.mandelbrot');
      expect(plan.assetId, 'mandelbrot');
      expect(plan.assetPath, 'assets/catalog_thumbs/mandelbrot.png');
    });

    test('preserves raw catalog IDs that are already asset IDs', () {
      final plan = CatalogThumbnailPlan.fromCatalogId('phoenix');

      expect(plan.assetId, 'phoenix');
      expect(plan.assetPath, 'assets/catalog_thumbs/phoenix.png');
    });
  });

  group('CatalogThumbnailLoadState', () {
    test('does not mark existing generated thumbnails approximate before error',
        () {
      for (final catalogId in ['core.nova', 'core.phoenix']) {
        final plan = CatalogThumbnailPlan.fromCatalogId(catalogId);
        expect(
          File(plan.assetPath).existsSync(),
          isTrue,
          reason: '${plan.assetPath} is the regression fixture',
        );

        const loading = CatalogThumbnailLoadState(
          imageLoaded: false,
          imageError: false,
        );
        const loaded = CatalogThumbnailLoadState(
          imageLoaded: true,
          imageError: false,
        );

        expect(loading.isApproximatePreview, isFalse, reason: catalogId);
        expect(loading.showsLoadingPlaceholder, isTrue, reason: catalogId);
        expect(loaded.isApproximatePreview, isFalse, reason: catalogId);
        expect(loaded.showsFallbackPreview, isFalse, reason: catalogId);
      }
    });

    test('marks only fallback thumbnails as approximate previews', () {
      const failed = CatalogThumbnailLoadState(
        imageLoaded: false,
        imageError: true,
      );

      expect(failed.showsLoadingPlaceholder, isFalse);
      expect(failed.showsFallbackPreview, isTrue);
      expect(failed.isApproximatePreview, isTrue);
    });
  });
}

